<?php
declare(strict_types=1);
require dirname(__DIR__).'/src/bootstrap.php';
require dirname(__DIR__).'/src/easyappointments.php';
if(!ea_enabled() && (app_setting('easyappointments_url')===''||app_setting('easyappointments_api_token_enc')===''))throw new RuntimeException('Easy!Appointments URL and token must be configured first.');
$email=trim((string)(getenv('PROVIDER_EMAIL')?:'dvillani@rapidanalyticsinc.com'));
$name=trim((string)(getenv('PROVIDER_NAME')?:'Daniel Villani'));$parts=preg_split('/\s+/',$name,2);
$serviceName=trim((string)(getenv('SERVICE_NAME')?:'30-Minute Consultation'));
$services=ea_request('GET','services',['q'=>$serviceName,'length'=>100]);$service=null;foreach($services as $row)if(strcasecmp((string)$row['name'],$serviceName)===0)$service=$row;
if(!$service)$service=ea_request('POST','services',[],['name'=>$serviceName,'duration'=>30,'price'=>0,'currency'=>'USD','location'=>'Online meeting','description'=>'A 30-minute consultation booked through OpenCRM.','availabilitiesType'=>'flexible','attendantsNumber'=>1,'isPrivate'=>false,'serviceCategoryId'=>null]);
$serviceId=(int)$service['id'];$providers=ea_request('GET','providers',['q'=>$email,'length'=>100]);$provider=null;foreach($providers as $row)if(strcasecmp((string)$row['email'],$email)===0)$provider=$row;
if(!$provider){$password=bin2hex(random_bytes(16));$working=['sunday'=>null,'monday'=>['start'=>'09:00','end'=>'17:00','breaks'=>[]],'tuesday'=>['start'=>'09:00','end'=>'17:00','breaks'=>[]],'wednesday'=>['start'=>'09:00','end'=>'17:00','breaks'=>[]],'thursday'=>['start'=>'09:00','end'=>'17:00','breaks'=>[]],'friday'=>['start'=>'09:00','end'=>'17:00','breaks'=>[]],'saturday'=>null];$provider=ea_request('POST','providers',[],['firstName'=>$parts[0],'lastName'=>$parts[1]??'Provider','email'=>$email,'mobile'=>'','phone'=>'','address'=>'','city'=>'','zip'=>'','notes'=>'OpenCRM provider','timezone'=>'America/New_York','language'=>'english','isPrivate'=>false,'ldapDn'=>null,'services'=>[$serviceId],'settings'=>['username'=>'opencrm_'.preg_replace('/[^a-z0-9]/','',strtolower($parts[0])),'password'=>$password,'notifications'=>true,'calendarView'=>'default','googleSync'=>false,'googleCalendar'=>null,'googleToken'=>null,'caldavSync'=>false,'caldavUrl'=>null,'caldavUsername'=>null,'caldavPassword'=>null,'syncFutureDays'=>90,'syncPastDays'=>30,'workingPlan'=>$working]]);}
$providerId=(int)$provider['id'];$user=db()->prepare('SELECT id FROM users WHERE LOWER(email)=? OR is_admin=1 ORDER BY LOWER(email)=? DESC,is_admin DESC LIMIT 1');$user->execute([strtolower($email),strtolower($email)]);$userId=(int)$user->fetchColumn();
$calendar=db()->prepare('SELECT id FROM booking_calendars WHERE external_provider_id=? LIMIT 1');$calendar->execute([$providerId]);$calendarId=(int)$calendar->fetchColumn();if(!$calendarId){db()->prepare("INSERT INTO booking_calendars(name,owner_user_id,external_provider_id,calendar_type,timezone,created_by) VALUES(?,?,?,'individual','America/New_York',?)")->execute([$name.' Calendar',$userId?:null,$providerId,$userId?:null]);$calendarId=(int)db()->lastInsertId();foreach([1,2,3,4,5] as $day)db()->prepare("INSERT INTO booking_availability_rules(calendar_id,weekday,start_time,end_time) VALUES(?,?,'09:00:00','17:00:00')")->execute([$calendarId,$day]);}
$meeting=db()->prepare('SELECT id FROM booking_meeting_types WHERE external_service_id=? AND calendar_id=? LIMIT 1');$meeting->execute([$serviceId,$calendarId]);$meetingId=(int)$meeting->fetchColumn();if(!$meetingId){db()->prepare("INSERT INTO booking_meeting_types(calendar_id,name,external_service_id,slug,description,duration_minutes,minimum_notice_hours,location_type,location_details,tag_ids,created_by) VALUES(?,?,?,?,?,30,4,'video','Online meeting','[]',?)")->execute([$calendarId,$serviceName,$serviceId,'consultation-30','A 30-minute consultation.',$userId?:null]);$meetingId=(int)db()->lastInsertId();}
echo json_encode(['provider_id'=>$providerId,'service_id'=>$serviceId,'calendar_id'=>$calendarId,'meeting_type_id'=>$meetingId],JSON_PRETTY_PRINT).PHP_EOL;
